# solution.py
"""CollaborativeProjectHub - Team Collaboration Manager.

A social-networking style collaboration platform for professionals and
enthusiasts. The module exposes a single facade -- ``TeamCollaborationManager``
-- that coordinates user profiles, project teams, task management, messaging,
a reputation/feedback system and reporting.

Design goals
------------
* **Thread safety** - every public operation runs under a single shared
  re-entrant lock that is exposed to each sub-store, so the whole object graph
  is mutated atomically and concurrent callers never observe a torn state.
* **Encapsulation** - every getter returns a deep copy so callers can never
  mutate the internal store by holding on to a returned object.
* **Deterministic clock** - the manager accepts an injectable ``now`` callable,
  which makes time-dependent behaviour (deadlines, completion timing, edit
  timestamps) fully testable.
* **Globally unique ids** - a single monotonic counter hands out ids across all
  entity types, so an id uniquely identifies an object platform-wide.

Only the Python standard library is used.
"""

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional, Tuple


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    """Platform roles. ``MEMBER`` is the default for new sign-ups."""

    MEMBER = "member"
    ADMIN = "admin"
    GUEST = "guest"


class ReportFormat(Enum):
    """Supported export formats for generated reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Discriminator stored on every generated report."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when caller-supplied input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current system state."""


# ---------------------------------------------------------------------------
# Data models
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    """A binary attachment stored against a message (metadata only)."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    """A platform member profile."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime
    skills: List[str] = field(default_factory=list)
    interests: List[str] = field(default_factory=list)
    availability: str = ""


@dataclass
class Project:
    """A collaborative project with an owner and a planned schedule."""

    id: int
    name: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    description: str = ""
    created_at: Optional[datetime] = None


@dataclass
class Task:
    """A unit of work inside a project."""

    id: int
    project_id: int
    title: str
    status: TaskStatus = TaskStatus.NOT_STARTED
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    description: str = ""
    created_at: Optional[datetime] = None


@dataclass
class Message:
    """A direct/group message attached to either a project or a task."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    """A peer rating/review contributing to a member's reputation."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str = ""
    task_id: Optional[int] = None
    created_at: Optional[datetime] = None


# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------
def _is_blank(value: object) -> bool:
    """Return True for None or strings that are empty after stripping."""

    return value is None or (isinstance(value, str) and value.strip() == "")


def _valid_email(email: str) -> bool:
    """A deliberately lightweight email check: single ``@`` with both sides."""

    if not isinstance(email, str):
        return False
    email = email.strip()
    if email.count("@") != 1:
        return False
    local, _, domain = email.partition("@")
    return bool(local) and bool(domain)


def _stringify(value: object) -> str:
    """Render a value as a flat string suitable for CSV/PDF cells."""

    if value is None:
        return ""
    if isinstance(value, datetime):
        return value.isoformat()
    if isinstance(value, Enum):
        return str(value.value)
    return str(value)


def _mean(values: List[float]) -> Optional[float]:
    """Arithmetic mean, or None for an empty sequence."""

    if not values:
        return None
    return sum(values) / len(values)


# ---------------------------------------------------------------------------
# Shared context
# ---------------------------------------------------------------------------
class _Context:
    """Owns every store, the shared lock, the id counter and the clock.

    A single instance is shared by reference across all sub-stores so that they
    all coordinate through one lock and one id sequence.
    """

    def __init__(self, now: Callable[[], datetime]):
        self.now = now
        self.lock = threading.RLock()
        self._id = 0
        self.users: Dict[int, User] = {}
        self.projects: Dict[int, Project] = {}
        self.tasks: Dict[int, Task] = {}
        self.messages: Dict[int, Message] = {}
        self.ratings: Dict[int, Rating] = {}

    # -- id allocation -----------------------------------------------------
    def next_id(self) -> int:
        self._id += 1
        return self._id

    # -- lookups (assume the shared lock is already held) ------------------
    def require_user(self, user_id: int) -> User:
        user = self.users.get(user_id)
        if user is None:
            raise NotFoundError("User {0} not found".format(user_id))
        return user

    def require_project(self, project_id: int) -> Project:
        project = self.projects.get(project_id)
        if project is None:
            raise NotFoundError("Project {0} not found".format(project_id))
        return project

    def require_task(self, task_id: int) -> Task:
        task = self.tasks.get(task_id)
        if task is None:
            raise NotFoundError("Task {0} not found".format(task_id))
        return task

    def require_message(self, message_id: int) -> Message:
        message = self.messages.get(message_id)
        if message is None:
            raise NotFoundError("Message {0} not found".format(message_id))
        return message

    # -- task metric helpers (assume the shared lock is already held) ------
    def tasks_for_assignee(self, user_id: int) -> List[Task]:
        tasks = [t for t in self.tasks.values() if t.assignee_id == user_id]
        tasks.sort(key=lambda t: t.id)
        return tasks

    def completion_durations(self, tasks: List[Task]) -> List[float]:
        durations = []
        for task in tasks:
            if (
                task.status == TaskStatus.COMPLETED
                and task.started_at is not None
                and task.completed_at is not None
            ):
                durations.append((task.completed_at - task.started_at).total_seconds())
        return durations

    def ratings_for_ratee(self, user_id: int) -> List[Rating]:
        ratings = [r for r in self.ratings.values() if r.ratee_id == user_id]
        ratings.sort(key=lambda r: r.id)
        return ratings


class _Store:
    """Base for every sub-store; shares the context's lock by reference."""

    def __init__(self, ctx: _Context):
        self._ctx = ctx
        self._lock = ctx.lock


# ---------------------------------------------------------------------------
# User store
# ---------------------------------------------------------------------------
class UserStore(_Store):
    """Profile management: registration, lookup, updates and removal."""

    def register(
        self,
        username: str,
        email: str,
        role: UserRole = UserRole.MEMBER,
        skills: Optional[List[str]] = None,
        interests: Optional[List[str]] = None,
        availability: str = "",
    ) -> User:
        if _is_blank(username):
            raise ValidationError("username must be a non-empty string")
        if _is_blank(email) or not _valid_email(email):
            raise ValidationError("email must be a valid address")
        if not isinstance(role, UserRole):
            raise ValidationError("role must be a UserRole")

        username = username.strip()
        email = email.strip()

        with self._lock:
            for existing in self._ctx.users.values():
                if existing.username == username:
                    raise DuplicateError("username already in use")
                if existing.email == email:
                    raise DuplicateError("email already in use")
            user = User(
                id=self._ctx.next_id(),
                username=username,
                email=email,
                role=role,
                created_at=self._ctx.now(),
                skills=list(skills or []),
                interests=list(interests or []),
                availability=availability,
            )
            self._ctx.users[user.id] = user
            return copy.deepcopy(user)

    def get(self, user_id: int) -> User:
        with self._lock:
            return copy.deepcopy(self._ctx.require_user(user_id))

    def list(self) -> List[User]:
        with self._lock:
            users = sorted(self._ctx.users.values(), key=lambda u: u.id)
            return [copy.deepcopy(u) for u in users]

    def update(
        self,
        user_id: int,
        username: Optional[str] = None,
        email: Optional[str] = None,
        role: Optional[UserRole] = None,
        skills: Optional[List[str]] = None,
        interests: Optional[List[str]] = None,
        availability: Optional[str] = None,
    ) -> User:
        with self._lock:
            user = self._ctx.require_user(user_id)

            if username is not None:
                if _is_blank(username):
                    raise ValidationError("username must be a non-empty string")
                new_username = username.strip()
                for other in self._ctx.users.values():
                    if other.id != user_id and other.username == new_username:
                        raise DuplicateError("username already in use")
                user.username = new_username

            if email is not None:
                if _is_blank(email) or not _valid_email(email):
                    raise ValidationError("email must be a valid address")
                new_email = email.strip()
                for other in self._ctx.users.values():
                    if other.id != user_id and other.email == new_email:
                        raise DuplicateError("email already in use")
                user.email = new_email

            if role is not None:
                if not isinstance(role, UserRole):
                    raise ValidationError("role must be a UserRole")
                user.role = role

            if skills is not None:
                user.skills = list(skills)
            if interests is not None:
                user.interests = list(interests)
            if availability is not None:
                user.availability = availability

            return copy.deepcopy(user)

    def delete(self, user_id: int) -> None:
        with self._lock:
            self._ctx.require_user(user_id)
            for project in self._ctx.projects.values():
                if project.owner_id == user_id:
                    raise ConflictError(
                        "user owns project {0}".format(project.id)
                    )
            for task in self._ctx.tasks.values():
                if (
                    task.assignee_id == user_id
                    and task.status != TaskStatus.COMPLETED
                ):
                    raise ConflictError(
                        "user has open task {0}".format(task.id)
                    )
            del self._ctx.users[user_id]


# ---------------------------------------------------------------------------
# Project store
# ---------------------------------------------------------------------------
class ProjectStore(_Store):
    """Project lifecycle including cascading deletes."""

    def create(
        self,
        name: str,
        start_date: datetime,
        end_date: datetime,
        owner_id: int,
        description: str = "",
    ) -> Project:
        with self._lock:
            self._ctx.require_user(owner_id)
            if _is_blank(name):
                raise ValidationError("project name must be a non-empty string")
            if start_date is None or end_date is None:
                raise ValidationError("start_date and end_date are required")
            if end_date < start_date:
                raise ValidationError("end_date cannot precede start_date")
            project = Project(
                id=self._ctx.next_id(),
                name=name.strip(),
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                description=description,
                created_at=self._ctx.now(),
            )
            self._ctx.projects[project.id] = project
            return copy.deepcopy(project)

    def get(self, project_id: int) -> Project:
        with self._lock:
            return copy.deepcopy(self._ctx.require_project(project_id))

    def list(self) -> List[Project]:
        with self._lock:
            projects = sorted(self._ctx.projects.values(), key=lambda p: p.id)
            return [copy.deepcopy(p) for p in projects]

    def update(
        self,
        project_id: int,
        name: Optional[str] = None,
        start_date: Optional[datetime] = None,
        end_date: Optional[datetime] = None,
        description: Optional[str] = None,
    ) -> Project:
        with self._lock:
            project = self._ctx.require_project(project_id)

            if name is not None:
                if _is_blank(name):
                    raise ValidationError(
                        "project name must be a non-empty string"
                    )
                project.name = name.strip()

            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end_date cannot precede start_date")
            project.start_date = new_start
            project.end_date = new_end

            if description is not None:
                project.description = description

            return copy.deepcopy(project)

    def delete(self, project_id: int) -> None:
        with self._lock:
            self._ctx.require_project(project_id)

            task_ids = [
                tid
                for tid, task in self._ctx.tasks.items()
                if task.project_id == project_id
            ]
            task_id_set = set(task_ids)
            for tid in task_ids:
                del self._ctx.tasks[tid]

            message_ids = [
                mid
                for mid, msg in self._ctx.messages.items()
                if msg.project_id == project_id or msg.task_id in task_id_set
            ]
            for mid in message_ids:
                del self._ctx.messages[mid]

            del self._ctx.projects[project_id]


# ---------------------------------------------------------------------------
# Task store
# ---------------------------------------------------------------------------
class TaskStore(_Store):
    """Task management that adapts to assignment and scheduling changes."""

    def create(
        self,
        project_id: int,
        title: str,
        assignee_id: Optional[int] = None,
        deadline: Optional[datetime] = None,
        description: str = "",
    ) -> Task:
        with self._lock:
            project = self._ctx.require_project(project_id)
            if assignee_id is not None:
                self._ctx.require_user(assignee_id)
            if _is_blank(title):
                raise ValidationError("task title must be a non-empty string")
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot precede project start")
            task = Task(
                id=self._ctx.next_id(),
                project_id=project_id,
                title=title.strip(),
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                description=description,
                created_at=self._ctx.now(),
            )
            self._ctx.tasks[task.id] = task
            return copy.deepcopy(task)

    def get(self, task_id: int) -> Task:
        with self._lock:
            return copy.deepcopy(self._ctx.require_task(task_id))

    def list_by_project(self, project_id: int) -> List[Task]:
        with self._lock:
            self._ctx.require_project(project_id)
            tasks = [
                t for t in self._ctx.tasks.values() if t.project_id == project_id
            ]
            tasks.sort(key=lambda t: t.id)
            return [copy.deepcopy(t) for t in tasks]

    def list_by_assignee(self, assignee_id: int) -> List[Task]:
        with self._lock:
            self._ctx.require_user(assignee_id)
            tasks = self._ctx.tasks_for_assignee(assignee_id)
            return [copy.deepcopy(t) for t in tasks]

    def assign(self, task_id: int, assignee_id: int) -> Task:
        with self._lock:
            task = self._ctx.require_task(task_id)
            self._ctx.require_user(assignee_id)
            task.assignee_id = assignee_id
            return copy.deepcopy(task)

    def reassign(self, task_id: int, new_assignee_id: int) -> Task:
        # Reassignment shares assignment semantics; kept separate for clarity
        # and so future policy (e.g. notifications) can diverge.
        return self.assign(task_id, new_assignee_id)

    def unassign(self, task_id: int) -> Task:
        with self._lock:
            task = self._ctx.require_task(task_id)
            task.assignee_id = None
            return copy.deepcopy(task)

    def set_deadline(self, task_id: int, deadline: Optional[datetime]) -> Task:
        with self._lock:
            task = self._ctx.require_task(task_id)
            if deadline is not None:
                project = self._ctx.projects.get(task.project_id)
                start = project.start_date if project is not None else None
                if start is not None and deadline < start:
                    raise ValidationError(
                        "deadline cannot precede project start"
                    )
            task.deadline = deadline
            return copy.deepcopy(task)

    def update_status(self, task_id: int, status: TaskStatus) -> Task:
        with self._lock:
            task = self._ctx.require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            now = self._ctx.now()

            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now

            task.status = status
            return copy.deepcopy(task)


# ---------------------------------------------------------------------------
# Message store
# ---------------------------------------------------------------------------
class MessageStore(_Store):
    """Direct/group messaging with threaded replies and attachments."""

    def post(
        self,
        author_id: int,
        body: str,
        project_id: Optional[int] = None,
        task_id: Optional[int] = None,
        parent_id: Optional[int] = None,
        attachments: Optional[List[Tuple[str, bytes]]] = None,
    ) -> Message:
        with self._lock:
            self._ctx.require_user(author_id)

            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )
            if project_id is not None:
                self._ctx.require_project(project_id)
            if task_id is not None:
                self._ctx.require_task(task_id)
            if parent_id is not None:
                self._ctx.require_message(parent_id)

            attachment_specs = attachments or []
            if _is_blank(body) and not attachment_specs:
                raise ValidationError(
                    "message requires a body or at least one attachment"
                )

            now = self._ctx.now()
            built = [
                self._build_attachment(filename, data, author_id, now)
                for filename, data in attachment_specs
            ]
            message = Message(
                id=self._ctx.next_id(),
                author_id=author_id,
                body=body,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built,
                created_at=now,
                edited_at=None,
            )
            self._ctx.messages[message.id] = message
            return copy.deepcopy(message)

    def _build_attachment(
        self, filename: str, data: bytes, uploaded_by: int, when: datetime
    ) -> Attachment:
        if _is_blank(filename):
            raise ValidationError("attachment filename must be non-empty")
        try:
            size = len(data)
        except TypeError:
            raise ValidationError("attachment data must be sized")
        return Attachment(
            filename=filename,
            size=size,
            uploaded_by=uploaded_by,
            uploaded_at=when,
        )

    def edit(self, message_id: int, editor_id: int, new_body: str) -> Message:
        with self._lock:
            message = self._ctx.require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            if _is_blank(new_body):
                raise ValidationError("message body must be non-empty")
            message.body = new_body
            message.edited_at = self._ctx.now()
            return copy.deepcopy(message)

    def add_attachment(
        self, message_id: int, uploader_id: int, filename: str, data: bytes
    ) -> Message:
        with self._lock:
            message = self._ctx.require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError(
                    "only the author may attach to a message"
                )
            attachment = self._build_attachment(
                filename, data, uploader_id, self._ctx.now()
            )
            message.attachments.append(attachment)
            return copy.deepcopy(message)

    def list_by_project(self, project_id: int) -> List[Message]:
        with self._lock:
            self._ctx.require_project(project_id)
            messages = [
                m
                for m in self._ctx.messages.values()
                if m.project_id == project_id
            ]
            messages.sort(key=lambda m: m.id)
            return [copy.deepcopy(m) for m in messages]

    def list_by_task(self, task_id: int) -> List[Message]:
        with self._lock:
            self._ctx.require_task(task_id)
            messages = [
                m for m in self._ctx.messages.values() if m.task_id == task_id
            ]
            messages.sort(key=lambda m: m.id)
            return [copy.deepcopy(m) for m in messages]

    def delete(self, message_id: int, requester_id: int) -> None:
        with self._lock:
            message = self._ctx.require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError(
                    "only the author may delete a message"
                )
            del self._ctx.messages[message_id]


# ---------------------------------------------------------------------------
# Performance / reputation store
# ---------------------------------------------------------------------------
class PerformanceStore(_Store):
    """Per-user productivity metrics and the peer-rating reputation system."""

    def completion_rate(self, user_id: int) -> float:
        with self._lock:
            self._ctx.require_user(user_id)
            tasks = self._ctx.tasks_for_assignee(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            return completed / len(tasks)

    def average_completion_time(self, user_id: int) -> Optional[float]:
        with self._lock:
            self._ctx.require_user(user_id)
            tasks = self._ctx.tasks_for_assignee(user_id)
            return _mean(self._ctx.completion_durations(tasks))

    def submit_rating(
        self,
        rater_id: int,
        ratee_id: int,
        score: int,
        feedback: str = "",
        task_id: Optional[int] = None,
    ) -> Rating:
        with self._lock:
            self._ctx.require_user(rater_id)
            self._ctx.require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("users cannot rate themselves")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer 1..5")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None:
                self._ctx.require_task(task_id)
            rating = Rating(
                id=self._ctx.next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback,
                task_id=task_id,
                created_at=self._ctx.now(),
            )
            self._ctx.ratings[rating.id] = rating
            return copy.deepcopy(rating)

    def ratings_summary(self, user_id: int) -> dict:
        with self._lock:
            self._ctx.require_user(user_id)
            ratings = self._ctx.ratings_for_ratee(user_id)
            scores = [r.score for r in ratings]
            average = _mean(scores)
            return {
                "user_id": user_id,
                "count": len(ratings),
                "average": average if average is not None else 0.0,
                "ratings": [copy.deepcopy(r) for r in ratings],
            }

    def user_dashboard(self, user_id: int) -> dict:
        with self._lock:
            self._ctx.require_user(user_id)
            tasks = self._ctx.tasks_for_assignee(user_id)
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            completion_rate = completed / total if total else 0.0
            avg_time = _mean(self._ctx.completion_durations(tasks))

            ratings = self._ctx.ratings_for_ratee(user_id)
            scores = [r.score for r in ratings]
            rating_average = _mean(scores)

            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": avg_time,
                "rating_count": len(ratings),
                "rating_average": rating_average if rating_average is not None else 0.0,
            }


