_TEAM_COLUMNS = [
    "user_id",
    "username",
    "total_tasks",
    "completed_tasks",
    "completion_rate",
    "average_completion_time",
    "rating_count",
    "rating_average",
]


class ReportStore(_Store):
    """Aggregated reporting plus CSV/PDF export."""

    # -- internal metric helpers (assume lock held) ------------------------
    def _task_metrics(self, tasks: List[Task]) -> dict:
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        in_progress = sum(
            1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
        )
        not_started = sum(
            1 for t in tasks if t.status == TaskStatus.NOT_STARTED
        )
        completion_rate = completed / total if total else 0.0
        avg_time = _mean(self._ctx.completion_durations(tasks))
        return {
            "total_tasks": total,
            "completed_tasks": completed,
            "in_progress_tasks": in_progress,
            "not_started_tasks": not_started,
            "completion_rate": completion_rate,
            "average_completion_time": avg_time,
        }

    def _rating_metrics(self, user_id: int) -> dict:
        ratings = self._ctx.ratings_for_ratee(user_id)
        scores = [r.score for r in ratings]
        average = _mean(scores)
        return {
            "rating_count": len(ratings),
            "rating_average": average if average is not None else 0.0,
        }

    # -- reports -----------------------------------------------------------
    def project_progress(self, project_id: int) -> dict:
        with self._lock:
            self._ctx.require_project(project_id)
            tasks = [
                t for t in self._ctx.tasks.values() if t.project_id == project_id
            ]
            tasks.sort(key=lambda t: t.id)
            now = self._ctx.now()

            status_counts = {status.value: 0 for status in TaskStatus}
            overdue = 0
            per_assignee: Dict[int, dict] = {}
            for task in tasks:
                status_counts[task.status.value] += 1
                if (
                    task.deadline is not None
                    and task.deadline < now
                    and task.status != TaskStatus.COMPLETED
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id,
                        {"total": 0, "completed": 0, "in_progress": 0, "not_started": 0},
                    )
                    bucket["total"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        bucket["completed"] += 1
                    elif task.status == TaskStatus.IN_PROGRESS:
                        bucket["in_progress"] += 1
                    else:
                        bucket["not_started"] += 1

            total = len(tasks)
            completion_rate = (
                status_counts[TaskStatus.COMPLETED.value] / total
                if total
                else 0.0
            )
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance(self, project_id: Optional[int] = None) -> dict:
        with self._lock:
            if project_id is not None:
                self._ctx.require_project(project_id)
                scope_tasks = [
                    t
                    for t in self._ctx.tasks.values()
                    if t.project_id == project_id
                ]
            else:
                scope_tasks = list(self._ctx.tasks.values())

            user_ids = sorted(
                {
                    t.assignee_id
                    for t in scope_tasks
                    if t.assignee_id is not None and t.assignee_id in self._ctx.users
                }
            )

            rows = []
            for user_id in user_ids:
                user = self._ctx.users[user_id]
                user_tasks = [
                    t for t in scope_tasks if t.assignee_id == user_id
                ]
                metrics = self._task_metrics(user_tasks)
                rating_metrics = self._rating_metrics(user_id)
                rows.append(
                    {
                        "user_id": user_id,
                        "username": user.username,
                        "total_tasks": metrics["total_tasks"],
                        "completed_tasks": metrics["completed_tasks"],
                        "completion_rate": metrics["completion_rate"],
                        "average_completion_time": metrics["average_completion_time"],
                        "rating_count": rating_metrics["rating_count"],
                        "rating_average": rating_metrics["rating_average"],
                    }
                )

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "columns": list(_TEAM_COLUMNS),
                "rows": rows,
            }

    def individual_performance(self, user_id: int) -> dict:
        with self._lock:
            self._ctx.require_user(user_id)
            tasks = self._ctx.tasks_for_assignee(user_id)
            metrics = self._task_metrics(tasks)
            rating_metrics = self._rating_metrics(user_id)

            task_rows = []
            for task in tasks:
                task_rows.append(
                    {
                        "task_id": task.id,
                        "project_id": task.project_id,
                        "title": task.title,
                        "status": task.status.value,
                        "deadline": task.deadline,
                        "started_at": task.started_at,
                        "completed_at": task.completed_at,
                    }
                )

            report = {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": self._ctx.users[user_id].username,
                "tasks": task_rows,
            }
            report.update(metrics)
            report.update(rating_metrics)
            return report

    # -- export ------------------------------------------------------------
    def export(self, report: dict, fmt: ReportFormat):
        if not isinstance(report, dict):
            raise ValidationError("report must be a dict")
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")
        if fmt == ReportFormat.CSV:
            return self._to_csv(report)
        return self._to_pdf(report)

    def _to_csv(self, report: dict) -> str:
        output = io.StringIO()
        writer = csv.writer(output)
        rows = report.get("rows")
        if isinstance(rows, list):
            columns = report.get("columns")
            if not columns:
                columns = list(rows[0].keys()) if rows else ["value"]
            writer.writerow(columns)
            for row in rows:
                writer.writerow([_stringify(row.get(col, "")) for col in columns])
        else:
            writer.writerow(["field", "value"])
            for key, value in report.items():
                writer.writerow([key, _stringify(value)])
        return output.getvalue()

    def _report_to_lines(self, report: dict) -> List[str]:
        lines = ["CollaborativeProjectHub Report"]
        lines.append("Type: {0}".format(report.get("report_type", "report")))
        rows = report.get("rows")
        if isinstance(rows, list):
            columns = report.get("columns") or (
                list(rows[0].keys()) if rows else []
            )
            if columns:
                lines.append(" | ".join(str(c) for c in columns))
            for row in rows:
                lines.append(
                    " | ".join(_stringify(row.get(c, "")) for c in columns)
                )
        else:
            for key, value in report.items():
                if key == "report_type":
                    continue
                lines.append("{0}: {1}".format(key, _stringify(value)))
        return lines

    def _to_pdf(self, report: dict) -> bytes:
        return _build_pdf(self._report_to_lines(report))


def _build_pdf(lines: List[str]) -> bytes:
    """Build a minimal but structurally valid single-page PDF document."""

    def escape(text: str) -> str:
        return (
            text.replace("\\", "\\\\").replace("(", "\\(").replace(")", "\\)")
        )

    content_parts = ["BT", "/F1 12 Tf", "50 750 Td", "14 TL"]
    first = True
    safe_lines = lines or ["(empty report)"]
    for line in safe_lines:
        text = escape(str(line))
        if first:
            content_parts.append("({0}) Tj".format(text))
            first = False
        else:
            content_parts.append("T*")
            content_parts.append("({0}) Tj".format(text))
    content_parts.append("ET")
    content = "\n".join(content_parts).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        (
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>"
        ),
        b"<< /Length "
        + str(len(content)).encode("ascii")
        + b" >>\nstream\n"
        + content
        + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    pdf = bytearray()
    pdf += b"%PDF-1.4\n"
    offsets = []
    for index, obj in enumerate(objects, start=1):
        offsets.append(len(pdf))
        pdf += str(index).encode("ascii") + b" 0 obj\n" + obj + b"\nendobj\n"

    xref_offset = len(pdf)
    size = len(objects) + 1
    pdf += b"xref\n"
    pdf += b"0 " + str(size).encode("ascii") + b"\n"
    pdf += b"0000000000 65535 f \n"
    for offset in offsets:
        pdf += ("%010d 00000 n \n" % offset).encode("ascii")
    pdf += b"trailer\n<< /Size " + str(size).encode("ascii") + b" /Root 1 0 R >>\n"
    pdf += b"startxref\n" + str(xref_offset).encode("ascii") + b"\n%%EOF\n"
    return bytes(pdf)


