class TeamCollaborationManager:
    """Public facade aggregating every collaboration sub-system.

    Parameters
    ----------
    now:
        Optional zero-argument callable returning the current ``datetime``.
        Defaults to :func:`datetime.datetime.now`. Injecting a deterministic
        clock makes all time-based behaviour reproducible.
    """

    def __init__(self, now: Optional[Callable[[], datetime]] = None):
        self._now = now if now is not None else datetime.now
        self._ctx = _Context(self._now)
        self._lock = self._ctx.lock

        self.users = UserStore(self._ctx)
        self.projects = ProjectStore(self._ctx)
        self.tasks = TaskStore(self._ctx)
        self.messages = MessageStore(self._ctx)
        self.performance = PerformanceStore(self._ctx)
        self.reports = ReportStore(self._ctx)

    # -- user management ---------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER,
                       skills=None, interests=None, availability=""):
        return self.users.register(
            username, email, role, skills, interests, availability
        )

    def get_user(self, user_id):
        return self.users.get(user_id)

    def list_users(self):
        return self.users.list()

    def update_user(self, user_id, username=None, email=None, role=None,
                    skills=None, interests=None, availability=None):
        return self.users.update(
            user_id, username, email, role, skills, interests, availability
        )

    def delete_user(self, user_id):
        return self.users.delete(user_id)

    # -- project management ------------------------------------------------
    def create_project(self, name, start_date, end_date, owner_id, description=""):
        return self.projects.create(
            name, start_date, end_date, owner_id, description
        )

    def get_project(self, project_id):
        return self.projects.get(project_id)

    def list_projects(self):
        return self.projects.list()

    def update_project(self, project_id, name=None, start_date=None,
                       end_date=None, description=None):
        return self.projects.update(
            project_id, name, start_date, end_date, description
        )

    def delete_project(self, project_id):
        return self.projects.delete(project_id)

    # -- task management ---------------------------------------------------
    def create_task(self, project_id, title, assignee_id=None, deadline=None,
                    description=""):
        return self.tasks.create(
            project_id, title, assignee_id, deadline, description
        )

    def get_task(self, task_id):
        return self.tasks.get(task_id)

    def list_tasks_by_project(self, project_id):
        return self.tasks.list_by_project(project_id)

    def list_tasks_by_assignee(self, assignee_id):
        return self.tasks.list_by_assignee(assignee_id)

    def assign_task(self, task_id, assignee_id):
        return self.tasks.assign(task_id, assignee_id)

    def reassign_task(self, task_id, new_assignee_id):
        return self.tasks.reassign(task_id, new_assignee_id)

    def unassign_task(self, task_id):
        return self.tasks.unassign(task_id)

    def set_deadline(self, task_id, deadline):
        return self.tasks.set_deadline(task_id, deadline)

    def update_status(self, task_id, status):
        return self.tasks.update_status(task_id, status)

    # -- messaging ---------------------------------------------------------
    def post_message(self, author_id, body, project_id=None, task_id=None,
                     parent_id=None, attachments=None):
        return self.messages.post(
            author_id, body, project_id, task_id, parent_id, attachments
        )

    def edit_message(self, message_id, editor_id, new_body):
        return self.messages.edit(message_id, editor_id, new_body)

    def add_attachment(self, message_id, uploader_id, filename, data):
        return self.messages.add_attachment(
            message_id, uploader_id, filename, data
        )

    def list_messages_by_project(self, project_id):
        return self.messages.list_by_project(project_id)

    def list_messages_by_task(self, task_id):
        return self.messages.list_by_task(task_id)

    def delete_message(self, message_id, requester_id):
